CREATE TABLE "video2"."render_fragments" ("render_id" uuid NOT NULL, "segment_id" text NOT NULL, "attempt_number" integer NOT NULL, "completed_at" timestamptz, "failed_at" timestamptz, "last_error" text, "started_at" timestamptz NOT NULL, PRIMARY KEY ("render_id","segment_id","attempt_number") , FOREIGN KEY ("render_id") REFERENCES "video2"."renders"("id") ON UPDATE cascade ON DELETE restrict);COMMENT ON TABLE "video2"."render_fragments" IS E'Status tracking for individual fragments of a render';
